#!/usr/bin/env python
"""
Bootstrap: Capture-Transform Enumerator
Writes core/transform_enumerator.py + tests/test_transform_enumerator.py
Run: python bootstrap_capture_transform.py
"""
import base64, os, sys

# Root detection
if os.path.exists("core/universal_schema.py"):
    root = "."
elif os.path.exists("../core/universal_schema.py"):
    root = ".."
else:
    print("ERROR: Run from MABE root or one directory below."); sys.exit(1)

# core/transform_enumerator.py
_p = os.path.join(root, "core/transform_enumerator.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

# tests/test_transform_enumerator.py
_p = os.path.join(root, "tests/test_transform_enumerator.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

print("Done. Run: python -m pytest tests/test_transform_enumerator.py -v")